-- =============================================================================
-- Migration 019: Sync production with dev (schema + SCM data)
-- Aplica migrations 012-018 + dados SCM de uma so vez
-- Seguro para rodar uma unica vez em producao
-- =============================================================================

SET SQL_MODE = "NO_AUTO_VALUE_ON_ZERO";
START TRANSACTION;
SET time_zone = "+00:00";

-- ---------------------------------------------------------------------------
-- 012: local_scm column + scm table
-- ---------------------------------------------------------------------------

SET @col_exists = (SELECT COUNT(*) FROM INFORMATION_SCHEMA.COLUMNS
    WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = 'equipamentos' AND COLUMN_NAME = 'local_scm');
SET @sql = IF(@col_exists = 0,
    'ALTER TABLE `equipamentos` ADD COLUMN `local_scm` VARCHAR(100) DEFAULT NULL',
    'SELECT 1');
PREPARE stmt FROM @sql; EXECUTE stmt; DEALLOCATE PREPARE stmt;

CREATE TABLE IF NOT EXISTS `scm` (
    `id`              INT AUTO_INCREMENT PRIMARY KEY,
    `scm`             VARCHAR(100) NOT NULL,
    `data`            DATE,
    `atividade`       TEXT,
    `site`            VARCHAR(100),
    `cidade`          VARCHAR(100),
    `data_execucao`   DATE,
    `data_validacao`  DATE,
    `medicao`         VARCHAR(100),
    `origem`          VARCHAR(100),
    `segmento`        VARCHAR(100),
    `abertura`        VARCHAR(100),
    `status`          VARCHAR(50),
    `obs`             TEXT,
    `equipamento_id`  INT DEFAULT NULL,
    `created_at`      DATETIME DEFAULT CURRENT_TIMESTAMP,
    `updated_at`      DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    UNIQUE KEY `idx_scm_code` (`scm`),
    KEY `idx_scm_equipamento` (`equipamento_id`),
    KEY `idx_scm_status` (`status`),
    KEY `idx_scm_site` (`site`),
    CONSTRAINT `fk_scm_equipamento` FOREIGN KEY (`equipamento_id`)
        REFERENCES `equipamentos` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

UPDATE `equipamentos` SET `local_scm` = 'HUB RECREIO' WHERE `local` = 'RJOREC';
UPDATE `equipamentos` SET `local_scm` = 'HUB RAMOS' WHERE `local` = 'RJORMS';
