-- ---------------------------------------------------------------------------
-- 015: mercado column em equipamentos
-- ---------------------------------------------------------------------------

SET @col_exists = (SELECT COUNT(*) FROM INFORMATION_SCHEMA.COLUMNS
    WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = 'equipamentos' AND COLUMN_NAME = 'mercado');
SET @sql = IF(@col_exists = 0,
    'ALTER TABLE `equipamentos` ADD COLUMN `mercado` VARCHAR(50) DEFAULT NULL AFTER `local_scm`',
    'SELECT 1');
PREPARE stmt FROM @sql; EXECUTE stmt; DEALLOCATE PREPARE stmt;

UPDATE `equipamentos` SET `mercado` = 'Residencial' WHERE `local` IN (
    'RSDDTC','BMADTC','TRLDTC','PTSDTC','NRIDTC','SGODTC','RJORMS','RJOMNB',
    'RJOCPG','RJOSLC','RJOPIA','RJOBOT','RJOTIJ','RJOFRG','CPDGDTC',
    'MCEDTC','MESQDTC','VTADTC','VVADTC','SEADTC','RJOBPI','NITC2DTC',
    'PAV11DTC','BGU02DTC','PAV71DTC','SCZ16DTC','NITB9DTC','VTA OCT','VTA ARB'
);
UPDATE `equipamentos` SET `mercado` = 'Empresarial' WHERE `local` IN (
    'VTA-JM','VTAJM','RJO-GS','RJOGS','RJOEN','RJO-CRT','RJOCRT',
    'RJO-TP','RJOTP','MCE-BC','MCEBC','CPS-CL','CPSCL','TNG-BR','TNGBR'
);
UPDATE `equipamentos` SET `mercado` = 'Pessoal' WHERE `local` IN (
    'RJMIR91','RJDQC91'
);

-- ---------------------------------------------------------------------------
-- 016: rate_limits table
-- ---------------------------------------------------------------------------

CREATE TABLE IF NOT EXISTS `rate_limits` (
    `id` INT AUTO_INCREMENT PRIMARY KEY,
    `ip_address` VARCHAR(45) NOT NULL,
    `endpoint` VARCHAR(100) NOT NULL,
    `window_start` DATETIME NOT NULL,
    `attempt_count` INT NOT NULL DEFAULT 1,
    UNIQUE KEY `uk_rate_limit` (`ip_address`, `endpoint`, `window_start`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ---------------------------------------------------------------------------
-- 014: scm_items table + normalizacao
-- ---------------------------------------------------------------------------

CREATE TABLE IF NOT EXISTS `scm_items` (
    `id` int(11) NOT NULL AUTO_INCREMENT,
    `scm_id` int(11) NOT NULL,
    `servico` text DEFAULT NULL,
    `unidade` varchar(50) DEFAULT NULL,
    `valor` decimal(12,2) DEFAULT NULL,
    `qtde_execucao` decimal(12,3) DEFAULT NULL,
    `subtotal_execucao` decimal(12,2) DEFAULT NULL,
    PRIMARY KEY (`id`),
    KEY `idx_scm_items_scm_id` (`scm_id`),
    CONSTRAINT `fk_scm_items_scm` FOREIGN KEY (`scm_id`) REFERENCES `scm` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ---------------------------------------------------------------------------
-- 018: usuarios collation fix
-- ---------------------------------------------------------------------------

ALTER TABLE `usuarios`
    CONVERT TO CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;

-- ---------------------------------------------------------------------------
-- DADOS: scm
-- ---------------------------------------------------------------------------




COMMIT;

-- Verificacao final
SELECT 'Migration 019 concluida' AS status;
SELECT COUNT(*) AS total_scm FROM scm;
SELECT COUNT(*) AS total_scm_items FROM scm_items;

